main.go<pre><code>package main

import (
    "errors"
    "fmt"

    "github.com/tink3rlabs/magic/storage"
    magicerrors "github.com/tink3rlabs/magic/errors"
)

type Task struct {
    ID     string `json:"id"`
    Title  string `json:"title"`
    Status string `json:"status"`
}

func main() {
    // setup errors elided for brevity; the Search below shows real error handling
    store, _ := storage.StorageAdapterFactory{}.GetInstance(storage.MEMORY, nil)
    _ = store.Create(Task{ID: "1", Title: "Pour foundation", Status: "open"})

    var hits []Task
    if _, err := store.Search(&amp;hits, "id", "status:open", 10, ""); err != nil {
        var bad *magicerrors.BadRequest
        if errors.As(err, &amp;bad) {
            fmt.Println("bad filter:", bad.Message)
        }
        return
    }
    fmt.Printf("matched %d tasks\n", len(hits))
}
</code></pre> <p>Swap <code>storage.MEMORY</code> for <code>storage.SQL</code> (with a config map) and the same code runs against Postgres.</p>

main.go<pre><code>package main

import (
    "fmt"
    "log"

    "github.com/tink3rlabs/magic/storage"
    "github.com/tink3rlabs/magic/storage/search/lucene"
)

type Task struct {
    ID     string `json:"id"`
    Title  string `json:"title"`
    Status string `json:"status"`
}

func main() {
    // 1. Build an adapter. In-memory needs no config.
    adapter, err := storage.StorageAdapterFactory{}.GetInstance(storage.MEMORY, nil)
    if err != nil {
        log.Fatal(err)
    }

    // 2. Create some rows.
    for _, t := range []Task{
        {ID: "01", Title: "Pour foundations", Status: "done"},
        {ID: "02", Title: "Frame walls", Status: "in_progress"},
        {ID: "03", Title: "Run electrical", Status: "pending"},
    } {
        if err := adapter.Create(t); err != nil {
            log.Fatal(err)
        }
    }

    // 3. Fetch one by exact filter.
    var task Task
    if err := adapter.Get(&amp;task, map[string]any{"id": "02"}); err != nil {
        log.Fatal(err)
    }
    fmt.Println("got:", task)

    // 4. List a page of tasks, sorted by id.
    var page []Task
    cursor, err := adapter.List(&amp;page, "id", nil, 10, "")
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("listed:", len(page), "cursor:", cursor)

    // 5. Search with a Lucene filter.
    parser, err := lucene.NewParser(Task{})
    if err != nil {
        log.Fatal(err)
    }
    _ = parser // your HTTP handler would hold this across requests.

    var hits []Task
    cursor, err = adapter.Search(&amp;hits, "id", "status:in_progress", 10, "")
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("searched:", hits, "next:", cursor)
}
</code></pre> <pre><code>go run main.go
</code></pre> <p>You'll see:</p> <pre><code>got: {02 Frame walls in_progress}
listed: 3 cursor:
searched: [{02 Frame walls in_progress}] next:
</code></pre>

parser.go<pre><code>parser, err := lucene.NewParser(Task{})
if err != nil {
    return err
}
sql, params, err := parser.ParseToSQL("status:received AND amount:[100 TO 500]", "postgresql")
// sql:    "(\"status\" = ?) AND (\"amount\" BETWEEN ? AND ?)"
// params: []any{"received", "100", "500"}
</code></pre> <p><code>ParseToSQL</code> returns <code>?</code> placeholders for every provider; GORM's Postgres driver rewrites them to <code>$1, $2, …</code> when it executes the query.</p> <p>The same parser drives the storage adapter's <code>Search</code> method, so most code never calls <code>ParseToSQL</code> directly — you just pass the user's filter string through.</p> <p><code>NewParser</code> introspects the model struct once. Only fields with a <code>json</code> tag are searchable; <code>json:"-"</code> and untagged fields are excluded. The field's Go type controls how you query it:</p> Go type <code>ImplicitSearch</code>? Notes <code>string</code> yes Matched by bare terms like <code>foo</code> (across all string fields). <code>int</code>, <code>float64</code>, <code>time.Time</code>, <code>uuid.UUID</code> no Must be referenced explicitly: <code>created_at:[X TO Y]</code>. Map / slice / struct (JSONB) no Reachable via <code>field.subfield</code> syntax (see JSON paths). <p>Field names in the query are the JSON tag, not the Go field name.</p>

main.go<pre><code>package main

import (
    "embed"

    "todo-service/cmd"

    "github.com/tink3rlabs/magic/storage"
)

//go:generate go run build/generate.go
//go:embed config
var configFS embed.FS

func main() {
    storage.ConfigFs = configFS
    cmd.ConfigFS = configFS
    cmd.Execute()
}
</code></pre> <p><code>main.go</code> does almost nothing itself. The <code>//go:embed config</code> directive bakes the entire <code>config/</code> tree — <code>development.yaml</code>, the generated <code>openapi.json</code>, and crucially the <code>migrations/</code> directory — into the binary as an <code>embed.FS</code>. That filesystem is then handed to two places: <code>storage.ConfigFs</code>, which is where magic's storage package looks for the migration files at startup (this is what makes the Migrations section's SQL available at runtime, with no files to ship alongside the binary), and <code>cmd.ConfigFS</code>, which the <code>server</code> command reads <code>openapi.json</code> from to serve <code>/api-docs</code>. Then <code>cmd.Execute()</code> hands control to cobra.</p>

cmd/root.go<pre><code>package cmd

import (
    "embed"
    "fmt"
    "os"
    "strings"

    homedir "github.com/mitchellh/go-homedir"
    "github.com/spf13/cobra"
    "github.com/spf13/viper"

    "github.com/tink3rlabs/magic/logger"
)

var ConfigFS embed.FS
var cfgFile string
var rootCmd = &amp;cobra.Command{
    Use:   "",
    Short: "ToDo is a reference implementaion of a common service architecture",
    Long: `ToDo is a reference implementaion of a common service architecture brought to you with love by tink3rlabs.
Complete documentation is available at https://github.com/tink3rlabs/todo-service`,
}

func Execute() {
    if err := rootCmd.Execute(); err != nil {
        fmt.Println(err)
        os.Exit(1)
    }
}

func init() {
    cobra.OnInitialize(initConfig)
    rootCmd.PersistentFlags().StringVar(&amp;cfgFile, "config", "", "config file (default is $HOME/.todo.yaml)")
    if viperBindFlagsErr := viper.BindPFlags(rootCmd.Flags()); viperBindFlagsErr != nil {
        fmt.Println(viperBindFlagsErr)
        os.Exit(1)
    }
    rootCmd.AddCommand(serverCommand)
}

func initConfig() {
    // Don't forget to read config either from cfgFile or from home directory!
    if cfgFile != "" {
        // Use config file from the flag.
        viper.SetConfigFile(cfgFile)
    } else {
        // Find home directory.
        home, err := homedir.Dir()
        if err != nil {
            fmt.Println(err)
            os.Exit(1)
        }

        // Search config in home directory with name ".cobra" (without extension).
        viper.AddConfigPath(home)
        viper.SetConfigName(".todo")
    }

    viper.SetEnvPrefix("TODO")
    viper.SetEnvKeyReplacer(strings.NewReplacer("_", "."))
    viper.AutomaticEnv()
    if err := viper.ReadInConfig(); err != nil {
        fmt.Println("Can't read config:", err)
        os.Exit(1)
    }

    config := loggerConfig()
    logger.Init(config)
}

func loggerConfig() *logger.Config {
    // Fetch the log level and format from the config file
    levelStr := viper.GetString("logger.level")
    json := viper.GetBool("logger.json")

    return &amp;logger.Config{
        Level: logger.MapLogLevel(levelStr),
        JSON:  json,
    }
}
</code></pre> <p><code>root.go</code> defines the cobra root command and registers the <code>server</code> subcommand. The work happens in <code>initConfig</code>, run by <code>cobra.OnInitialize</code> before any command executes: it points viper at the config file (the <code>--config</code> flag, or <code>~/.todo.yaml</code> by default), enables <code>TODO_</code>-prefixed environment overrides, and reads the file. Every <code>viper.GetString(...)</code> call you'll see in <code>server.go</code> resolves against the config loaded here. Finally it calls <code>logger.Init</code> with the level and format from the config, so magic's structured logger is ready before the server starts.</p>
